#include <bits/stdc++.h>
using namespace std;
const int maxn=105,maxv=10005;
int n,m,a[maxn][2],b[maxn][maxv];
void dfs(int i,int s) {
	if(!i) {
		return;
	}
	for(int j=0; j<=1; j++) {
		if(s-a[i][j]>=0&&!b[i-1][s-a[i][j]]) {
			b[i-1][s-a[i][j]]=j+1;
			dfs(i-1,s-a[i][j]);
		}
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1; i<=n; i++) {
		cin>>a[i][0]>>a[i][1];
	}
	dfs(n,m);
	if(b[0][0]) {
		cout<<"Yes\n";
		for(int i=0,j=0; i!=n; j+=a[i+1][b[i][j]-1],i++) {
			cout<<(b[i][j]-1?'T':'H');
		}
	} else {
		cout<<"No";
	}
	return 0;
}
